package main

import (
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	case "linux", "darwin":
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		if exitErr, ok := err.(*exec.ExitError); ok {
			// Ping returned non-zero exit code but may have partial results
			output = exitErr.Stderr
		} else {
			return 0, fmt.Errorf("failed to execute ping command: %w", err)
		}
	}

	timePattern := regexp.MustCompile(`time=([\d.]+)\s*ms`)
	times := []float64{}
	lines := strings.Split(string(output), "\n")

	for _, line := range lines {
		matches := timePattern.FindStringSubmatch(line)
		if len(matches) < 2 {
			continue
		}

		timeVal, err := strconv.ParseFloat(matches[1], 64)
		if err != nil {
			continue // Skip invalid time values
		}
		times = append(times, timeVal)
	}

	if len(times) == 0 {
		return 0, fmt.Errorf("no successful ping responses received")
	}

	var sum float64
	for _, t := range times {
		sum += t
	}
	return sum / float64(len(times)), nil
}

