package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default: // Linux, macOS, etc.
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		// Check if we have any successful pings despite error
		matches := regexp.MustCompile(`time=([0-9.]+)\s*ms`).FindAllStringSubmatch(string(output), -1)
		if len(matches) == 0 {
			return 0, fmt.Errorf("ping command failed: %w", err)
		}
	}

	re := regexp.MustCompile(`time=([0-9.]+)\s*ms`)
	matches := re.FindAllStringSubmatch(string(output), -1)
	if len(matches) == 0 {
		return 0, errors.New("no valid ping responses")
	}

	var total float64
	for _, match := range matches {
		if len(match) < 2 {
			continue
		}
		timeStr := match[1]
		t, err := strconv.ParseFloat(timeStr, 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse time value: %s", timeStr)
		}
		total += t
	}

	avg := total / float64(len(matches))
	return avg, nil
}

func main() {
	if len(os.Args) < 3 {
		fmt.Println("Usage: go run main.go <host> <count>")
		return
	}
	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Println("Invalid count")
		return
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Average latency: %.2f ms\n", avg)
}

