package main

import (
	"bytes"
	"fmt"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
)

func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}

	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default: // Linux, macOS, BSD
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	var out bytes.Buffer
	cmd.Stdout = &out
	if err := cmd.Run(); err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	output := out.String()
	var avgLatency float64
	var found bool

	if runtime.GOOS == "windows" {
		lines := strings.Split(output, "\n")
		for _, line := range lines {
			if strings.Contains(line, "Average =") {
				parts := strings.Split(line, "=")
				if len(parts) < 2 {
					continue
				}
				valuePart := strings.TrimSpace(parts[len(parts)-1])
				valuePart = strings.TrimSuffix(valuePart, "ms")
				valuePart = strings.TrimSpace(valuePart)
				if avg, err := strconv.ParseFloat(valuePart, 64); err == nil {
					avgLatency = avg
					found = true
					break
				}
			}
		}
	} else {
		lines := strings.Split(output, "\n")
		for _, line := range lines {
			if strings.Contains(line, "rtt min/avg/max/mdev") || strings.Contains(line, "round-trip min/avg/max/mdev") {
				parts := strings.Split(line, "=")
				if len(parts) < 2 {
					continue
				}
				stats := strings.Split(strings.TrimSpace(parts[1]), "/")
				if len(stats) >= 4 {
					if avg, err := strconv.ParseFloat(stats[1], 64); err == nil {
						avgLatency = avg
						found = true
						break
					}
				}
			}
		}
	}

	if !found {
		return 0, fmt.Errorf("failed to parse average latency from ping output")
	}

	return avgLatency, nil
}

func main() {
	// Example usage
	avg, err := MeasureLatency("google.com", 4)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}
	fmt.Printf("Average latency: %.2f ms\n", avg)
}

