package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

func MeasureLatency(host string, count int) (float64, error) {
	if count < 1 {
		return 0, fmt.Errorf("count must be at least 1")
	}

	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default: // linux, darwin, etc.
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	var out bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &out

	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v, output: %s", err, out.String())
	}

	output := out.String()

	switch runtime.GOOS {
	case "windows":
		re := regexp.MustCompile(`Average = ([\d.]+)ms`)
		matches := re.FindStringSubmatch(output)
		if matches == nil || len(matches) < 2 {
			return 0, fmt.Errorf("failed to parse average from ping output: %s", output)
		}
		avgStr := matches[1]
		avg, err := strconv.ParseFloat(avgStr, 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse average value: %v", err)
		}
		return avg, nil
	default:
		re := regexp.MustCompile(`(\d+\.?\d*)/(\d+\.?\d*)/(\d+\.?\d*)/(\d+\.?\d*)\s*ms`)
		matches := re.FindStringSubmatch(output)
		if matches == nil || len(matches) < 5 {
			return 0, fmt.Errorf("failed to parse average from ping output: %s", output)
		}
		avgStr := matches[2]
		avg, err := strconv.ParseFloat(avgStr, 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse average value: %v", err)
		}
		return avg, nil
	}
}

func main() {
	if len(os.Args) != 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Fprintf(os.Stderr, "Invalid count: %v\n", err)
		os.Exit(1)
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avg)
}

