func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be at least 1")
	}

	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default: // linux, darwin, etc.
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v, output: %s", err, string(output))
	}

	outputStr := string(output)

	switch runtime.GOOS {
	case "windows":
		re := regexp.MustCompile(`Average = ([0-9.]+)ms`)
		matches := re.FindStringSubmatch(outputStr)
		if len(matches) < 2 {
			return 0, fmt.Errorf("could not find average latency in ping output")
		}
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse average latency: %v", err)
		}
		return avg, nil

	default: // unix systems
		lines := strings.Split(outputStr, "\n")
		for _, line := range lines {
			if strings.Contains(line, "min/avg/max") || strings.Contains(line, "rtt min/avg/max") {
				idx := strings.Index(line, "=")
				if idx == -1 {
					continue
				}
				rest := line[idx+1:]
				fields := strings.Fields(rest)
				if len(fields) == 0 {
					continue
				}
				rttData := fields[0]
				numbers := strings.Split(rttData, "/")
				if len(numbers) < 4 {
					continue
				}
				avg, err := strconv.ParseFloat(numbers[1], 64)
				if err != nil {
					continue
				}
				return avg, nil
			}
		}
		return 0, fmt.Errorf("could not find latency summary in ping output")
	}
}

func main() {
	if len(os.Args) != 3 {
		fmt.Println("Usage: latency <host> <count>")
		os.Exit(1)
	}

