func MeasureLatency(host string, count int) (float64, error) {
	if count < 1 {
		return 0, errors.New("count must be at least 1")
	}

	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil && len(output) == 0 {
		return 0, fmt.Errorf("ping command failed: %v", err)
	}

	times, _ := parsePingOutput(string(output))
	if len(times) == 0 {
		if err != nil {
			return 0, fmt.Errorf("ping command failed: %v; no successful pings", err)
		}
		return 0, errors.New("no successful pings")
	}

	total := 0.0
	for _, t := range times {
		total += t
	}
	return total / float64(len(times)), nil
}

func parsePingOutput(output string) ([]float64, error) {
	re := regexp.MustCompile(`time[=:<](\d+(?:\.\d+)?)\s?ms`)
	matches := re.FindAllStringSubmatch(output, -1)
	times := make([]float64, 0, len(matches))

	for _, match := range matches {
		if len(match) < 2 {
			continue
		}
		timeStr := strings.TrimSpace(match[1])
		t, err := strconv.ParseFloat(timeStr, 64)
		if err != nil {
			continue
		}
		times = append(times, t)
	}
	return times, nil
}

func main() {
	if len(os.Args) != 3 {
		fmt.Println("Usage: pingutil <host> <count>")
		os.Exit(1)
	}
	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Println("Count must be an integer")
		os.Exit(1)
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Average latency: %.2f ms\n", avg)
}

