package main

import (
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count < 1 {
		return 0, fmt.Errorf("count must be at least 1")
	}

	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default: // Linux, macOS, etc.
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil && len(output) == 0 {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	re := regexp.MustCompile(`time=(\d+(?:\.\d+)?)\s?ms`)
	matches := re.FindAllStringSubmatch(string(output), -1)
	if len(matches) == 0 {
		return 0, fmt.Errorf("no valid ping responses found in output")
	}

	var total float64
	validCount := 0
	for _, match := range matches {
		if len(match) < 2 {
			continue
		}
		t, err := strconv.ParseFloat(match[1], 64)
		if err != nil {
			continue // Skip invalid numbers
		}
		total += t
		validCount++
	}

	if validCount == 0 {
		return 0, fmt.Errorf("no parseable latency values found")
	}

	return total / float64(validCount), nil
}

func main() {
	if len(os.Args) != 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Fprintf(os.Stderr, "Invalid count: %s\n", os.Args[2])
		os.Exit(1)
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency: %.2f ms\n", avg)
}

