import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default: // Linux, macOS, BSD, etc.
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		// Check if we have a non-zero exit code (like packet loss) but still got some responses
		if _, ok := err.(*exec.ExitError); !ok {
			return 0, fmt.Errorf("failed to execute ping command: %w", err)
		}
	}

	// Parse the output to extract latency times
	var pattern string
	if runtime.GOOS == "windows" {
		pattern = `time=(\d+)ms`
	} else {
		pattern = `time=(\d+(?:\.\d+)?)\s*ms`
	}

	re := regexp.MustCompile(pattern)
	lines := strings.Split(string(output), "\n")
	var times []float64

	for _, line := range lines {
		matches := re.FindStringSubmatch(line)
		if len(matches) < 2 {
			continue
		}

		timeStr := matches[1]
		t, err := strconv.ParseFloat(timeStr, 64)
		if err != nil {
			continue // Skip unparseable values
		}
		times = append(times, t)
	}

	if len(times) == 0 {
		if err != nil {
			return 0, fmt.Errorf("no packets received: %w", err)
		}
		return 0, errors.New("no packets received")
	}

	// Calculate average
	var sum float64
	for _, t := range times {
		sum += t
	}
	return sum / float64(len(times)), nil
}

func main() {
	if len(os.Args) < 3 {
		fmt.Printf("Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Printf("Invalid count: %v\n", err)
		os.Exit(1)
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency: %.2f ms\n", avg)
}

