						avg, err = strconv.ParseFloat(timeStr, 64)
						if err != nil {
							return 0, fmt.Errorf("could not parse average time: %v", err)
						}
						found = true
						break
					}
				}
				break
			}
		}
	} else {
		lines := strings.Split(output, "\n")
		for _, line := range lines {
