				parts := strings.Split(line, " ")
				for _, p := range parts {
					if strings.Contains(p, "/") {
						stats := strings.Split(p, "/")
						if len(stats) >= 4 {
							avg, err = strconv.ParseFloat(stats[1], 64)
							if err != nil {
								return 0, fmt.Errorf("could not parse average time: %v", err)
							}
							found = true
							break
						}
					}
				}
				break
			}
		}
	}

	if !found {
		return 0, fmt.Errorf("could not find average latency in ping output")
	}

	return avg, nil
}

func main() {
	if len(os.Args) < 3 {
		fmt.Println("Usage: go run main.go <host> <count>")
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
