package main

import (
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

var timeRegex = regexp.MustCompile(`time=(\d+\.?\d*)\s?ms`)

func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}

	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", host, "-n", strconv.Itoa(count))
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		// Proceed to parse output even if command returned error
	}

	lines := strings.Split(string(output), "\n")
	var times []float64
	for _, line := range lines {
		matches := timeRegex.FindStringSubmatch(line)
		if matches != nil {
			t, err := strconv.ParseFloat(matches[1], 64)
			if err == nil {
				times = append(times, t)
			}
		}
	}

	if len(times) == 0 {
		if err != nil {
			return 0, err
		}
		return 0, fmt.Errorf("no valid ping responses")
	}

	var sum float64
	for _, t := range times {
		sum += t
	}
	average := sum / float64(len(times))
	return average, nil
}

func main() {
	if len(os.Args) != 3 {
		fmt.Printf("Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Printf("Invalid count: %v\n", err)
		os.Exit(1)
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avg)
}

