package main

import (
	"bytes"
	"fmt"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count < 1 {
		return 0, fmt.Errorf("count must be at least 1")
	}

	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	case "darwin", "linux":
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	var out bytes.Buffer
	cmd.Stdout = &out
	if err := cmd.Run(); err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	output := out.String()
	var avgRtt float64
	var found bool

	if runtime.GOOS == "windows" {
		lines := strings.Split(output, "\n")
		for _, line := range lines {
			if strings.Contains(line, "Average =") {
				parts := strings.Split(line, "Average = ")
				if len(parts) < 2 {
					continue
				}
				avgPart := strings.TrimSpace(parts[1])
				avgPart = strings.TrimSuffix(avgPart, "ms")
				avgPart = strings.TrimSpace(avgPart)
				avg, err := strconv.ParseFloat(avgPart, 64)
				if err == nil {
					avgRtt = avg
					found = true
					break
				}
			}
		}
	} else {
		lines := strings.Split(output, "\n")
		for _, line := range lines {
			if strings.Contains(line, "rtt min/avg/max/mdev") {
				parts := strings.Split(line, " = ")
				if len(parts) < 2 {
					continue
				}
				stats := strings.Split(parts[1], "/")
				if len(stats) >= 4 {
					avg, err := strconv.ParseFloat(stats[1], 64)
					if err == nil {
						avgRtt = avg
						found = true
						break
					}
				}
			}
		}
	}

	if !found {
		return 0, fmt.Errorf("failed to parse average latency from ping output")
	}

	return avgRtt, nil
}

func main() {
	// Example usage
	avg, err := MeasureLatency("google.com", 4)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Average latency: %.2f ms\n", avg)
}

