func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	var output bytes.Buffer
	cmd.Stdout = &output
	cmd.Stderr = &output

	if err := cmd.Run(); err != nil {
		return 0, fmt.Errorf("ping command failed: %v\n%s", err, output.String())
	}

	avg, err := parsePingOutput(output.String(), runtime.GOOS)
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %v", err)
	}
	return avg, nil
}

func parsePingOutput(output string, os string) (float64, error) {
	lines := strings.Split(output, "\n")

	if os == "windows" {
		for _, line := range lines {
			if strings.Contains(line, "Average =") {
				parts := strings.Split(line, "Average =")
				if len(parts) < 2 {
					continue
				}
				avgStr := strings.TrimSpace(parts[1])
				avgStr = strings.ReplaceAll(avgStr, "ms", "")
				avgStr = strings.Fields(avgStr)[0]
				avg, err := strconv.ParseFloat(avgStr, 64)
				if err != nil {
					return 0, fmt.Errorf("failed to parse average: %v", err)
				}
				return avg, nil
			}
		}
	} else {
		for i := len(lines) - 1; i >= 0; i-- {
			line := lines[i]
			if strings.Contains(line, "min/avg/max") || strings.Contains(line, "rtt min/avg/max") {
				parts := strings.Split(line, " = ")
				if len(parts) < 2 {
					continue
				}
				stats := strings.Fields(parts[1])[0]
				values := strings.Split(stats, "/")
				if len(values) < 4 {
					return 0, fmt.Errorf("unexpected ping statistics format")
				}
				avg, err := strconv.ParseFloat(values[1], 64)
				if err != nil {
					return 0, fmt.Errorf("failed to parse average: %v", err)
				}
				return avg, nil
			}
		}
	}

	return 0, fmt.Errorf("average latency not found in ping output")
}

func main() {
	if len(os.Args) != 3 {
		fmt.Println("Usage: latency <host> <count>")
		os.Exit(1)
