func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	case "darwin", "linux":
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	var out bytes.Buffer
	cmd.Stdout = &out
	if err := cmd.Run(); err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	output := out.String()
	switch runtime.GOOS {
	case "windows":
		return parseWindowsOutput(output)
	case "darwin", "linux":
		return parseUnixOutput(output)
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}
}

func parseWindowsOutput(output string) (float64, error) {
	lines := strings.Split(output, "\n")
	for i := len(lines) - 1; i >= 0; i-- {
		line := lines[i]
		if strings.Contains(line, "Average =") {
			parts := strings.Split(line, "Average =")
			if len(parts) < 2 {
				continue
			}
			valStr := strings.TrimSpace(parts[1])
			valStr = strings.TrimSuffix(valStr, "ms")
			valStr = strings.TrimSpace(valStr)
			avg, err := strconv.ParseFloat(valStr, 64)
			if err != nil {
				return 0, fmt.Errorf("failed to parse average value: %w", err)
			}
			return avg, nil
		}
	}
	return 0, fmt.Errorf("could not find average latency in ping output")
}

func parseUnixOutput(output string) (float64, error) {
	lines := strings.Split(output, "\n")
	for i := len(lines) - 1; i >= 0; i-- {
		line := lines[i]
		if strings.Contains(line, "min/avg/max/") || strings.Contains(line, "round-trip min/avg/max/") {
			fields := strings.Fields(line)
			if len(fields) < 4 {
				continue
			}
			stats := strings.Split(fields[3], "/")
			if len(stats) < 4 {
				continue
			}
			avg, err := strconv.ParseFloat(stats[1], 64)
			if err != nil {
				return 0, fmt.Errorf("failed to parse average value: %w", err)
			}
			return avg, nil
		}
	}
	return 0, fmt.Errorf("could not find average latency in ping output")
}

func main() {
	// Example usage
	avg, err := MeasureLatency("google.com", 4)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Average latency: %.2f ms\n", avg)
}

