	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %s", err)
	}

	switch runtime.GOOS {
	case "linux", "darwin":
		return parseLinuxOutput(string(output))
	case "windows":
		return parseWindowsOutput(string(output))
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}
}

func parseLinuxOutput(output string) (float64, error) {
	lines := strings.Split(output, "\n")
	for _, line := range lines {
		if strings.Contains(line, "min/avg/max") || strings.Contains(line, "round-trip") {
			tokens := strings.Fields(line)
			for i, token := range tokens {
				if token == "=" && i+1 < len(tokens) {
					numbersToken := tokens[i+1]
					parts := strings.Split(numbersToken, "/")
					if len(parts) < 3 {
						continue
					}
					avg, err := strconv.ParseFloat(parts[1], 64)
					if err != nil {
						return 0, fmt.Errorf("could not parse average value: %s", parts[1])
					}
					return avg, nil
				}
			}
		}
	}
	return 0, errors.New("failed to parse ping output: no average latency found")
}

func parseWindowsOutput(output string) (float64, error) {
	re := regexp.MustCompile(`Average\s*=\s*([\d.]+)ms`)
	matches := re.FindStringSubmatch(output)
	if matches == nil {
		return 0, errors.New("failed to parse ping output: no average latency found")
	}
	avg, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("could not parse average value: %s", matches[1])
	}
	return avg, nil
}

func main() {
	if len(os.Args) < 3 {
